@namespace sv_99482e7e98344ea6887de0e892a38d18.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var stepIndex = i;
        var status = GetStepStatus(stepIndex);
        <button class="step @status"
                disabled="@(status == "future")"
                @onclick="() => OnStepClick(stepIndex)"
                aria-current="@(status == "current" ? "step" : null)">
            <span class="step-number">
                @if (status == "completed")
                {
                    <span class="checkmark">&#10003;</span>
                }
                else
                {
                    @(stepIndex + 1)
                }
            </span>
            <span class="step-label">@StepNames[stepIndex]</span>
        </button>
        @if (stepIndex < StepNames.Count - 1)
        {
            <span class="step-connector @(stepIndex < CurrentStep ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnNavigateToStep { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private string GetStepStatus(int index)
    {
        if (index == CurrentStep) return "current";
        if (index < CurrentStep) return "completed";
        return "future";
    }

    private async Task OnStepClick(int stepIndex)
    {
        if (stepIndex < CurrentStep)
        {
            await OnNavigateToStep.InvokeAsync(stepIndex);
        }
    }
}

@namespace sv_99482e7e98344ea6887de0e892a38d18.Components.Pages.Apply

<div class="work-entry-form">
    <div class="work-entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (ShowRemove)
        {
            <button type="button" class="btn-remove" @onclick="OnRemove">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Company Name *</label>
        <input type="text" value="@Entry.Company"
               @onchange="e => Update(Entry with { Company = e.Value?.ToString() ?? "" })" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" value="@Entry.Title"
               @onchange="e => Update(Entry with { Title = e.Value?.ToString() ?? "" })" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                   @onchange="e => Update(Entry with { StartDate = DateTime.Parse(e.Value?.ToString() ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" value="@(Entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                   disabled="@IsCurrent"
                   @onchange="e => Update(Entry with { EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!) })" />
            <label class="checkbox-label">
                <input type="checkbox" checked="@IsCurrent" @onchange="OnCurrentChanged" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" value="@Entry.Description"
                  @onchange="e => Update(Entry with { Description = e.Value?.ToString() ?? "" })"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnEntryChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate == null && Entry.StartDate != default;

    private async Task Update(WorkEntry updated)
    {
        await OnEntryChanged.InvokeAsync(updated);
    }

    private async Task OnCurrentChanged(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        var updated = isCurrent
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        await OnEntryChanged.InvokeAsync(updated);
    }
}

@namespace sv_99482e7e98344ea6887de0e892a38d18.Components.Pages.Apply

<div class="reference-form">
    <h4>Reference @(Index + 1)</h4>

    <div class="form-group">
        <label>Name *</label>
        <input type="text" value="@Reference.Name"
               @onchange="e => Update(Reference with { Name = e.Value?.ToString() ?? "" })" />
    </div>

    <div class="form-group">
        <label>Relationship *</label>
        <input type="text" value="@Reference.Relationship"
               @onchange="e => Update(Reference with { Relationship = e.Value?.ToString() ?? "" })" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Email *</label>
            <input type="email" value="@Reference.Email"
                   @onchange="e => Update(Reference with { Email = e.Value?.ToString() ?? "" })" />
        </div>

        <div class="form-group">
            <label>Phone</label>
            <input type="tel" value="@Reference.Phone"
                   @onchange="e => Update(Reference with { Phone = e.Value?.ToString() ?? "" })" />
        </div>
    </div>

    @if (ShowRemove)
    {
        <button type="button" class="btn-remove" @onclick="OnRemove">Remove</button>
    }
</div>

@code {
    [Parameter, EditorRequired] public Reference Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<Reference> OnReferenceChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private async Task Update(Reference updated)
    {
        await OnReferenceChanged.InvokeAsync(updated);
    }
}

