@namespace sv_99482e7e98344ea6887de0e892a38d18.Components.Pages.Apply

<div class="step-content">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" @bind="FullName" />
    </div>

    <div class="form-group">
        <label>Email *</label>
        <input type="email" @bind="Email" />
        @if (!string.IsNullOrEmpty(emailError))
        {
            <span class="field-error">@emailError</span>
        }
    </div>

    <div class="form-group">
        <label>Phone *</label>
        <input type="tel" @bind="Phone" />
    </div>

    <div class="form-group">
        <label>Address *</label>
        <textarea rows="2" @bind="Address"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(validationError))
    {
        <div class="validation-error">@validationError</div>
    }

    <div class="step-actions">
        <button class="btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @(isValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? validationError;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            validationError = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var isEmailValid = await ValidateEmail(Email);
            if (!isEmailValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync(new PersonalInfo(FullName, Email, Phone, Address));
        }
        finally
        {
            isValidating = false;
        }
    }
}

@namespace sv_99482e7e98344ea6887de0e892a38d18.Components.Pages.Apply

<div class="step-content">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="@Entries[index]"
                       Index="index"
                       ShowRemove="@(Entries.Count > 1)"
                       OnEntryChanged="e => UpdateEntry(index, e)"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">
        + Add Another Position
    </button>

    @if (!string.IsNullOrEmpty(validationError))
    {
        <div class="validation-error">@validationError</div>
    }

    <div class="step-actions">
        <button class="btn-outline" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntry> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void UpdateEntry(int index, WorkEntry updated)
    {
        Entries[index] = updated;
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                validationError = "Company name and job title are required for all entries.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
}

@namespace sv_99482e7e98344ea6887de0e892a38d18.Components.Pages.Apply

<div class="step-content">
    <h2>References</h2>
    <p class="step-description">Please provide 2–3 professional references.</p>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="@References[index]"
                       Index="index"
                       ShowRemove="@(References.Count > 2)"
                       OnReferenceChanged="r => UpdateReference(index, r)"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-secondary" @onclick="AddReference">
            + Add Reference
        </button>
    }

    @if (!string.IsNullOrEmpty(validationError))
    {
        <div class="validation-error">@validationError</div>
    }

    <div class="step-actions">
        <button class="btn-outline" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<Reference> References { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<Reference>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void UpdateReference(int index, Reference updated)
    {
        References[index] = updated;
    }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new Reference("", "", "", ""));
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationError = null;

        if (References.Count < 2)
        {
            validationError = "At least 2 references are required.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email))
            {
                validationError = "Name, relationship, and email are required for all references.";
                return;
