    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> OnSubmit { get; set; } = default!;

    private bool isSubmitting;
    private bool IsSubmitted;
    private int ApplicationId;
    private string? submitError;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            ApplicationId = await OnSubmit();
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}
