@namespace sv_99482e7e98344ea6887de0e892a38d18.Components.Pages.Apply

<div class="step-content">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" @bind="FullName" />
    </div>

    <div class="form-group">
        <label>Email *</label>
        <input type="email" @bind="Email" />
        @if (!string.IsNullOrEmpty(emailError))
        {
            <span class="field-error">@emailError</span>
        }
    </div>

    <div class="form-group">
        <label>Phone *</label>
        <input type="tel" @bind="Phone" />
    </div>

    <div class="form-group">
        <label>Address *</label>
        <textarea rows="2" @bind="Address"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(validationError))
    {
        <div class="validation-error">@validationError</div>
    }

    <div class="step-actions">
        <button class="btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @(isValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? validationError;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            validationError = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var isEmailValid = await ValidateEmail(Email);
            if (!isEmailValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync(new PersonalInfo(FullName, Email, Phone, Address));
        }
        finally
        {
            isValidating = false;
        }
    }
}

