@namespace sv_99482e7e98344ea6887de0e892a38d18.Components.Pages.Apply

<div class="step-content">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="@Entries[index]"
                       Index="index"
                       ShowRemove="@(Entries.Count > 1)"
                       OnEntryChanged="e => UpdateEntry(index, e)"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">
        + Add Another Position
    </button>

    @if (!string.IsNullOrEmpty(validationError))
    {
        <div class="validation-error">@validationError</div>
    }

    <div class="step-actions">
        <button class="btn-outline" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntry> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void UpdateEntry(int index, WorkEntry updated)
    {
        Entries[index] = updated;
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                validationError = "Company name and job title are required for all entries.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
}

