@page "/apply"
@using sv_99482e7e98344ea6887de0e892a38d18.Services
@using sv_99482e7e98344ea6887de0e892a38d18.Components.Pages.Apply
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="application-form">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="currentStep" OnNavigateToStep="NavigateToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@personalInfo.FullName"
                              Email="@personalInfo.Email"
                              Phone="@personalInfo.Phone"
                              Address="@personalInfo.Address"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="HandlePersonalInfoNext" />
            break;

        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="HandleWorkHistoryNext"
                             OnBack="GoBack" />
            break;

        case 2:
            <ReferencesStep References="references"
                            OnNext="HandleReferencesNext"
                            OnBack="GoBack" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="GoBack" />
            break;

        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        OnEditSection="NavigateToStep"
                        OnBack="GoBack"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep = 0;

    private PersonalInfo personalInfo = new("", "", "", "");
    private List<WorkEntry> workEntries = new() { new("", "", DateTime.Today, null, "") };
    private List<Reference> references = new() { new("", "", "", ""), new("", "", "", "") };
    private string coverLetter = "";

    private void NavigateToStep(int step)
    {
        if (step >= 0 && step <= 4)
        {
            currentStep = step;
        }
    }

    private void GoBack()
    {
        if (currentStep > 0) currentStep--;
    }

    private void HandlePersonalInfoNext(PersonalInfo info)
    {
        personalInfo = info;
        currentStep = 1;
    }

    private void HandleWorkHistoryNext(List<WorkEntry> entries)
    {
        workEntries = entries;
        currentStep = 2;
    }

    private void HandleReferencesNext(List<Reference> refs)
    {
        references = refs;
        currentStep = 3;
    }

    private void HandleCoverLetterNext(string letter)
    {
        coverLetter = letter;
        currentStep = 4;
    }

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo,
            new WorkHistory(workEntries),
            references,
            coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

